type GeoAiInspectCardState = {
  title: string;
  rows: { label: string; value: string }[];
  /** Rich popup layout (sections, tabs, search) when built from layer identify. */
  inspect?: SiPopupInspectPayload | null;
  lng: number;
  lat: number;
  areaName?: string;
  country?: string;
};

type GeoAiIdentifyCandidateState = SatelliteIdentifyCandidate;

type GeoAiInspectPopupState = GeoAiInspectCardState & {
  id: string;
  pinned: boolean;
  collapsed: boolean;
  featureLinkKey: string | null;
  identifyCandidates?: GeoAiIdentifyCandidateState[];
  activeCandidateId?: string;
  editMode?: boolean;
};

function getMapIdentifyPopupLink(pop: GeoAiInspectPopupState): GeoExplorerMapLink | null {
  const activeId = pop.activeCandidateId ?? pop.identifyCandidates?.[0]?.id;
  const cand = pop.identifyCandidates?.find(c => c.id === activeId);
  if (cand?.tableLink) return cand.tableLink;
  const fk = cand?.featureLinkKey ?? pop.featureLinkKey;
  if (fk?.includes('::')) {
    const sep = fk.indexOf('::');
    const layerId = fk.slice(0, sep);
    const featureKey = fk.slice(sep + 2);
    if (layerId && featureKey) return { type: 'feature', layerId, featureKey };
  }
  return null;
}

function resolveMapIdentifyPopupLayer(
  pop: GeoAiInspectPopupState,
  layers: { id: string | number; name?: string; color?: string; fillColor?: string }[],
) {
  const link = getMapIdentifyPopupLink(pop);
  if (link?.type === 'feature') {
    return layers.find(l => String(l.id) === link.layerId);
  }
  const layerId = pop.featureLinkKey?.includes('::') ? pop.featureLinkKey.split('::')[0] : null;
  if (layerId) return layers.find(l => String(l.id) === layerId);
  return undefined;
}

function resolveMapIdentifyPopupFeature(
  pop: GeoAiInspectPopupState,
  layers: Parameters<typeof resolveGeoAiFeatureFromLink>[1],
): GeoJSON.Feature | null {
  const link = getMapIdentifyPopupLink(pop);
  if (link?.type !== 'feature') return null;
  const layer = layers.find(l => String(l.id) === link.layerId);
  const feats = layer?.geojson?.features;
  if (!Array.isArray(feats)) return null;
  for (let i = 0; i < feats.length; i++) {
    const f = feats[i] as GeoJSON.Feature;
    if (computeStableGisFeatureKey(f, i) !== link.featureKey) continue;
    return {
      type: 'Feature',
      geometry: f.geometry ?? { type: 'Point', coordinates: [pop.lng, pop.lat] },
      properties:
        f.properties && typeof f.properties === 'object' && !Array.isArray(f.properties)
          ? { ...(f.properties as Record<string, unknown>) }
          : {},
    };
  }
  return null;
}

function resolveMapIdentifyPopupProperties(
  pop: GeoAiInspectPopupState,
  layers: Parameters<typeof resolveGeoAiFeatureFromLink>[1],
): Record<string, unknown> | null {
  const link = getMapIdentifyPopupLink(pop);
  if (link?.type !== 'feature') return null;
  return resolveGeoAiFeatureFromLink(link, layers)?.properties ?? null;
}

function siRowKeyForFeatureLink(
  link: Extract<GeoExplorerMapLink, { type: 'feature' }>,
  layer: { geojson?: { features?: unknown[] } | null },
  cache: Map<object, string>,
): string | null {
  const feats = layer?.geojson?.features;
  if (!Array.isArray(feats)) return null;
  for (let i = 0; i < feats.length; i++) {
    const f = feats[i];
    if (computeStableGisFeatureKey(f, i) === link.featureKey) {
      return siComputeFeatureRowKey(f, i, cache);
    }
  }
  return null;
}

function siResolveRowPropertyKey(label: string, properties: Record<string, unknown>): string {
  if (Object.prototype.hasOwnProperty.call(properties, label)) return label;
  const lower = label.toLowerCase();
  for (const k of Object.keys(properties)) {
    if (k.toLowerCase() === lower) return k;
  }
  return label;
}

type GeoAiPopupMode = 'single' | 'multiple' | 'docked' | 'side';

const GEO_AI_POPUP_MODE_LS_KEY = 'si-geo-ai-popup-mode-v1';

